const l=JSON.parse('{"key":"v-389d7eb8","path":"/project/%E4%B8%80%E9%94%AE%E7%94%9F%E6%88%90%E5%AE%9E%E9%AA%8C%E6%8A%A5%E5%91%8Aword%E6%96%87%E6%A1%A3.html","title":"根据实验流程数据一键生成64页的实验报告word文档","lang":"zh-CN","frontmatter":{"title":"根据实验流程数据一键生成64页的实验报告word文档","isTimeLine":true,"date":"2026-03-09T00:00:00.000Z","category":["后端"],"tag":["JavaScript","nodejs"]},"headers":[{"level":3,"title":"场景","slug":"场景","link":"#场景","children":[]},{"level":3,"title":"难点","slug":"难点","link":"#难点","children":[]},{"level":3,"title":"解决方案","slug":"解决方案","link":"#解决方案","children":[]},{"level":3,"title":"实现","slug":"实现","link":"#实现","children":[]},{"level":3,"title":"坑点","slug":"坑点","link":"#坑点","children":[]}],"git":{"createdTime":1773506313000,"updatedTime":1773618690000,"contributors":[{"name":"liunal","email":"liunal","commits":2}]},"readingTime":{"minutes":3.99,"words":1196},"filePathRelative":"project/一键生成实验报告word文档.md","localizedDate":"2026年3月9日","excerpt":"<h3> 场景</h3>\\n<ol>\\n<li>做实验的最终目的是得出一个包括各个过程的报告，</li>\\n<li>走完前面的任务创建、样品采样、数据录入、选择实验工具、结果计算各个流程后，最后是生成报告的流程。</li>\\n<li>拿到了前面各个流程的数据，报告就可以一键生成且在页面上预览。</li>\\n</ol>\\n<h3> 难点</h3>\\n<ol>\\n<li>报告内容包括实验步骤说明、表格、复杂表格、图片列表、结论等等，印象比较深的是导出一份64页的报告，都是表格数据与结论。</li>\\n<li>不同子类型的检测项目报告内容差异很大，所以需要定制多个报告模板，生成报告时选择对应的模板生成数据。</li>\\n</ol>"}');export{l as data};
